<?phpsession_start();require_once "../api/db.php";/* Redirect if not logged in */if (!isset($_SESSION["user_id"])) {    header("Location: ../index.html");    exit;}$user_id = $_SESSION["user_id"];$search_ticket = trim($_GET["ticket"] ?? "");/* Query bugs for this user */if ($search_ticket !== "") {    $sql = "SELECT bug_id, title, severity, status, created_at            FROM bugs            WHERE created_by = ? AND bug_id = ?            ORDER BY created_at DESC";    $stmt = $conn->prepare($sql);    $stmt->bind_param("ii", $user_id, $search_ticket);} else {    $sql = "SELECT bug_id, title, severity, status, created_at            FROM bugs            WHERE created_by = ?            ORDER BY created_at DESC";    $stmt = $conn->prepare($sql);    $stmt->bind_param("i", $user_id);}$stmt->execute();$result = $stmt->get_result();function severityLabel($severity) {    switch ($severity) {        case 1: return "1 - Low";        case 2: return "2 - Medium";        case 3: return "3 - High";        case 4: return "4 - Critical";        default: return $severity;    }}?><!DOCTYPE html><html lang="en"><head>  <meta charset="UTF-8" />  <meta name="viewport" content="width=device-width, initial-scale=1.0" />  <title>My Bugs - BugOut</title>  <link rel="stylesheet" href="../css/style.css" /></head><body class="mybugs-page">  <div class="mybugs-grid">   <a href="user.html" class="mybugs-card mybugs-logo-card logo-link">  <img src="../assets/logo.png" alt="BugOut Logo" class="mybugs-logo" /></a>    <div class="mybugs-card mybugs-title-card">      <h2>        <span class="green-text">My</span>        <span class="purple-text">Bugs</span>      </h2>    </div>    <div class="mybugs-card mybugs-search-card">      <form class="ticket-search-form" action="mybugs.php" method="GET">        <label for="ticketSearch">          <span class="blue-text">Search Ticket Number:</span>        </label>        <input          type="text"          id="ticketSearch"          name="ticket"          placeholder="Enter Ticket Number"          value="<?php echo htmlspecialchars($search_ticket); ?>"        />      </form>    </div>    <div class="mybugs-card mybugs-history-card">      <h2>        <span class="purple-text">Bug</span>        <span class="green-text">History</span>      </h2>      <img src="../assets/logo.png" alt="Bug Icon" class="history-bug-img" />    </div>    <div class="mybugs-card mybugs-table-card">      <div class="table-wrapper">        <table class="mybugs-table">          <thead>            <tr>              <th>Ticket Number</th>              <th>Title</th>              <th>Priority</th>              <th>Status</th>              <th>Date</th>              <th>Action</th>            </tr>          </thead>          <tbody>            <?php if ($result->num_rows > 0): ?>              <?php while ($row = $result->fetch_assoc()): ?>                <tr>                  <td><?php echo htmlspecialchars($row["bug_id"]); ?></td>                  <td><?php echo htmlspecialchars($row["title"]); ?></td>                  <td><?php echo htmlspecialchars(severityLabel((int)$row["severity"])); ?></td>                  <td><?php echo htmlspecialchars($row["status"]); ?></td>                  <td><?php echo htmlspecialchars(date("Y-m-d", strtotime($row["created_at"]))); ?></td>                  <td>                    <a href="status.php?bug_id=<?php echo $row["bug_id"]; ?>" class="view-link">View</a>                  </td>                </tr>              <?php endwhile; ?>            <?php else: ?>              <tr>                <td colspan="6">No bugs found.</td>              </tr>            <?php endif; ?>          </tbody>        </table>      </div>    </div>  </div></body></html>